async function handleRequest(request) {
  if (request.method !== 'POST') {
    return new Response('Method not allowed', { status: 405 });
  }

  const url = new URL(request.url);
  const path = url.pathname;

  try {
    if (path === '/auth/login') {
      return await handleLogin(request);
    } else if (path === '/auth/validate') {
      return await handleValidate(request);
    } else if (path === '/auth/logout') {
      return await handleLogout(request);
    } else {
      return new Response('Not found', { status: 404 });
    }
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

async function handleLogin(request) {
  const body = await request.json();
  const { username, password } = body;

  if (!username || !password) {
    return new Response(JSON.stringify({ error: 'Username and password required' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  const userKey = `user:${username}`;
  const userData = await USERS_DB.get(userKey, { type: 'json' });

  if (!userData) {
    return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  const passwordHash = await hashPassword(password, userData.salt);
  
  if (passwordHash !== userData.passwordHash) {
    return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  const sessionToken = await generateSessionToken();
  const sessionData = {
    username: username,
    userId: userData.userId,
    createdAt: Date.now(),
    expiresAt: Date.now() + (24 * 60 * 60 * 1000)
  };

  await SESSIONS.put(`session:${sessionToken}`, JSON.stringify(sessionData), {
    expirationTtl: 86400
  });

  return new Response(JSON.stringify({
    success: true,
    sessionToken: sessionToken,
    username: username,
    expiresAt: sessionData.expiresAt
  }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' }
  });
}

async function handleValidate(request) {
  const body = await request.json();
  const { sessionToken } = body;

  if (!sessionToken) {
    return new Response(JSON.stringify({ error: 'Session token required' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  const sessionData = await SESSIONS.get(`session:${sessionToken}`, { type: 'json' });

  if (!sessionData) {
    return new Response(JSON.stringify({ valid: false, error: 'Invalid session' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  if (Date.now() > sessionData.expiresAt) {
    await SESSIONS.delete(`session:${sessionToken}`);
    return new Response(JSON.stringify({ valid: false, error: 'Session expired' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  return new Response(JSON.stringify({
    valid: true,
    username: sessionData.username,
    userId: sessionData.userId,
    expiresAt: sessionData.expiresAt
  }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' }
  });
}

async function handleLogout(request) {
  const body = await request.json();
  const { sessionToken } = body;

  if (!sessionToken) {
    return new Response(JSON.stringify({ error: 'Session token required' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  await SESSIONS.delete(`session:${sessionToken}`);

  return new Response(JSON.stringify({ success: true }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' }
  });
}

async function generateSessionToken() {
  const buffer = new Uint8Array(32);
  crypto.getRandomValues(buffer);
  return Array.from(buffer, byte => byte.toString(16).padStart(2, '0')).join('');
}

async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const data = encoder.encode(password + salt);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(byte => byte.toString(16).padStart(2, '0')).join('');
}

async function createUser(username, password) {
  const salt = await generateSessionToken();
  const passwordHash = await hashPassword(password, salt);
  const userId = await generateSessionToken();
  
  const userData = {
    userId: userId,
    username: username,
    passwordHash: passwordHash,
    salt: salt,
    createdAt: Date.now()
  };

  await USERS_DB.put(`user:${username}`, JSON.stringify(userData));
  return userData;
}